mapper.select:
SELECT cm.*, p.name AS plant_name
FROM chatbot_messages cm
LEFT JOIN plants p ON p.id = cm.plant_id
WHERE cm.user_id = #{userId}
AND cm.plant_id = #{plantId}
ORDER BY cm.created_at DESC, cm.id DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM chatbot_messages
WHERE id = #{id}
  AND user_id = #{userId}

DELETE FROM chatbot_messages
WHERE user_id = #{userId}
  AND plant_id = #{plantId}
